import csv
from torch.utils.data import Dataset, DataLoader
#custom dataset
class CustomDataset(Dataset):
    """Tokenize data when we call __getitem__"""
    def __init__(self, path, tokenizer):
        with open(path, newline="") as f:
            reader = csv.reader(f)
            next(reader) # skip the heading
            self.data = [{"source": row[0], "target": row[4]} for row in reader]
        self.tokenizer = tokenizer

    def __getitem__(self, i):

        inputs = self.tokenizer(self.data[i]['source'])
        labels = self.tokenizer(self.data[i]['target'])
        inputs['labels'] = labels.input_ids
        return inputs

import csv
from torch.utils.data import Dataset
import torch

class CustomDataset(Dataset):
    """Custom Dataset for binary text classification."""

    def __init__(self, path, tokenizer, max_length=128):
        with open(path, newline="") as f:
            reader = csv.reader(f)
            next(reader)  # Skip header
            self.data = [{"text": row[0], "label": int(row[4])} for row in reader]

        self.tokenizer = tokenizer
        self.max_length = max_length

    def __len__(self):
        return len(self.data)

    def __getitem__(self, i):
        text = self.data[i]['text']
        label = self.data[i]['label']

        inputs = self.tokenizer(
            text,
            truncation=True,
            padding='max_length',
            max_length=self.max_length,
            return_tensors="pt"
        )

        # Flatten batch dimension and add label
        return {
            'input_ids': inputs['input_ids'].squeeze(0),
            'attention_mask': inputs['attention_mask'].squeeze(0),
            'label': torch.tensor(label, dtype=torch.long)
        }

